    37→static void emit(double x)
    38→{
    39→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += erf(vx);
    41→}
    42→
    43→static void emit_u(uint64_t bits)
    44→{
    45→    emit(u2d(bits));
    46→}
    47→#else
    48→static void emit(double x)
    49→{
    50→    double r = erf(x);
    51→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    52→}
