    60→/* ------------------------------------------------------------------ */
    61→/* Representative 100-point test                                       */
    62→/* ------------------------------------------------------------------ */
    63→
    64→static void test_representative_100(void)
    65→{
    66→    /* --- Section 1: Special IEEE 754 values (7) --- */
    67→    emit(0.0);
    68→    emit(-0.0);
    69→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    70→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    71→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    72→    emit_u(0x7ff0000000000000ULL);  /* +Inf -> erf = +1 */
    73→    emit_u(0xfff0000000000000ULL);  /* -Inf -> erf = -1 */
    74→
    75→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    76→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    77→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    78→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    79→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    80→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    81→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    82→
    83→    /* --- Section 3: Normal boundary values (4) --- */
    84→    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    85→    emit(-DBL_MIN);
    86→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    87→    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: 0x7fefffffffffffff -> erf saturates to 1 */
    88→
    89→    /* --- Section 4: Near 1.0 density (8) --- */
    90→    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    91→    emit(1.0);
    92→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    93→    emit_u(0x3fefffff00000000ULL);  /* a few ULPs below 1.0 */
    94→    emit_u(0x3ff0000100000000ULL);  /* a few ULPs above 1.0 */
    95→    emit(-1.0);
    96→    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    97→    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    98→
    99→    /* --- Section 5: Exponent switching points (6) --- */
   100→    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
   101→    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
   102→    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
   103→    emit_u(0x4000000000000000ULL);  /* 2.0 */
   104→    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
   105→    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
   106→
   107→    /* --- Section 6: erf-specific mathematical values (14) --- */
   108→    /* erf known exact/near-exact results */
   109→    emit(0.5);                      /* erf(0.5) ~ 0.5205 */
   110→    emit(-0.5);
   111→    emit(1.5);                      /* erf(1.5) ~ 0.9661 */
   112→    emit(-1.5);
   113→    emit(2.0);                      /* erf(2.0) ~ 0.9953 */
   114→    emit(-2.0);
   115→    emit(0.1);                      /* erf near-linear region */
   116→    emit(-0.1);
   117→    emit(0.01);
   118→    emit(-0.01);
   119→    emit(0.001);
   120→    emit(-0.001);
   121→    emit_u(0x3fe20dd750429b6dULL);  /* 2/sqrt(pi) ~ 1.1284: argument where Taylor is exact */
   122→    emit_u(0xbfe20dd750429b6dULL);  /* negative of above */
   123→
   124→    /* --- Section 7: Saturation region (8) --- */
   125→    emit(2.5);                      /* erf(2.5) ~ 0.99959 */
   126→    emit(-2.5);
   127→    emit(3.0);                      /* erf(3.0) ~ 0.99998 */
   128→    emit(-3.0);
   129→    emit(4.0);                      /* erf(4.0) rounds to 1.0 in double */
   130→    emit(-4.0);
   131→    emit(5.0);                      /* erf(5.0) = 1.0 to double precision */
   132→    emit(-5.0);
   133→
   134→    /* --- Section 8: ULP neighbors of key transition points (12) --- */
   135→    /* erf transitions from polynomial to asymptotic near x = 0.84 (erfinv(0.5)) */
   136→    /* and again near x ~ 1.0 (polynomial switchover in many implementations) */
   137→    emit_u(0x3feae89f995ad3adULL);  /* erfinv(0.5) ~ 0.4769: lower polynomial boundary */
   138→    emit_u(0x3feae89f995ad3aeULL);  /* one ULP above */
   139→    emit_u(0x3feae89f995ad3acULL);  /* one ULP below */
   140→    /* x ~ sqrt(2): another implementation branch */
   141→    emit_u(0x3ff6a09e667f3bccULL);  /* sqrt(2) - 1 ULP */
   142→    emit_u(0x3ff6a09e667f3bcdULL);  /* sqrt(2) */
   143→    emit_u(0x3ff6a09e667f3bceULL);  /* sqrt(2) + 1 ULP */
   144→    /* near x = 4.0: saturation boundary (center covered by Section 7) */
   145→    emit_u(0x400ffffffffffffeULL);  /* 4.0 - 2 ULP */
   146→    emit_u(0x400fffffffffffffULL);  /* 4.0 - 1 ULP */
   147→    emit_u(0x4010000000000001ULL);  /* 4.0 + 1 ULP */
   148→    /* near x = 0.0: critical for linear approx */
   149→    emit_u(0x3cb0000000000000ULL);  /* 2^-52: one ULP of 1.0, tests tiny-arg path */
   150→    emit_u(0x3c90000000000000ULL);  /* 2^-54 */
   151→    emit_u(0xbc90000000000000ULL);  /* -2^-54 */
   152→
   153→    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
   154→    /* Many implementations use erf(x) ~ (2/sqrt(pi))*x below a threshold */
   155→    emit_u(0x3fb0000000000000ULL);  /* 2^-4 ~ 0.0625 */
   156→    emit_u(0xbfb0000000000000ULL);  /* -2^-4 */
   157→    emit_u(0x3f50000000000000ULL);  /* 2^-10 ~ 0.000977 */
   158→    emit_u(0xbf50000000000000ULL);  /* -2^-10 */
   159→    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ 1.49e-8 */
   160→    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
   161→    emit_u(0x3c00000000000000ULL);  /* 2^-63: extremely small, erf(x) ~ x */
   162→    emit_u(0xbc00000000000000ULL);  /* -2^-63 */
   163→
   164→    /* --- Section 10: Hard cases and polynomial branch points (27) --- */
   165→    /* Large values beyond saturation: erf = +-1 exactly */
   166→    emit(10.0);
   167→    emit(-10.0);
   168→    emit(100.0);
   169→    emit(-100.0);
   170→    /* Intermediate values spanning polynomial regions (quarter-integer grid) */
   171→    emit(0.25);
   172→    emit(-0.25);
   173→    emit(0.75);
   174→    emit(-0.75);
   175→    emit(1.25);
   176→    emit(-1.25);
   177→    emit(1.75);
   178→    emit(-1.75);
   179→    emit(2.25);
   180→    emit(-2.25);
   181→    emit(2.75);
   182→    emit(-2.75);
   183→    emit(3.5);
   184→    emit(-3.5);
   185→    /* Power-of-2 inputs: clean exponent boundaries */
   186→    emit(8.0);
   187→    emit(-8.0);
   188→    /* ULP neighbors of exact integer arguments not covered above */
   189→    emit_u(0x3ff0000000000002ULL);  /* 1.0 + 2 ULP */
   190→    emit_u(0x4000000000000002ULL);  /* 2.0 + 2 ULP */
   191→    emit_u(0x4007ffffffffffffULL);  /* 3.0 - 1 ULP */
   192→    emit_u(0x4010000000000002ULL);  /* 4.0 + 2 ULP */
   193→    emit_u(0x4014000000000001ULL);  /* 5.0 + 1 ULP */
   194→    emit(6.0);                      /* well into saturation, intermediate large value */
   195→    emit(-6.0);
   196→}
