   200→#ifndef EN_PERF
   201→/* 7. Sweep [-10, 10] in 200 steps */
   202→static void test_sweep(void)
   203→{
   204→    double hi = 10.0;
   205→    int nsteps = 200;
   206→    double step = hi / (double)nsteps;
   207→
   208→    /* [-10, 10] */
   209→    for (int i = -nsteps; i <= nsteps; i++)
   210→        emit((double)i * step);
   211→}
   212→
   213→/* 8. Sample [0, 5] every 4194304 ULP (~250 cases) */
   214→static void test_exhaustive_small(void)
   215→{
   216→    static const uint64_t vals[] = {
   217→        0x0000000000000000ULL, /* 0.0 */
   218→        0x3fe0000000000000ULL, /* 0.5 */
   219→        0x3ff0000000000000ULL, /* 1.0 */
   220→        0x3ff8000000000000ULL, /* 1.5 */
   221→        0x4000000000000000ULL, /* 2.0 */
   222→        0x4008000000000000ULL, /* 3.0 */
   223→        0x4010000000000000ULL, /* 4.0 */
   224→        0x4014000000000000ULL, /* 5.0 */
   225→    };
   226→    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
   227→        emit_u(vals[i]);
   228→}
   229→
   230→/* 9. Random sweep: 300 evenly spaced inputs */
   231→static void test_random_300(void)
   232→{
   233→    double lo = -3.0;
   234→    double hi =  3.0;
   235→    int n = 300;
   236→    for (int i = 0; i < n; i++) {
   237→        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
   238→        emit(x);
   239→    }
   240→}
   241→#endif
